def count_vowels(text):
    count = 0
    for ch in text.lower():
        if ch in "aeiou":
            count = count + 1
    return count

print(count_vowels("Computer Science"))

def summary(marks):
    return max(marks), min(marks), sum(marks) / len(marks)

high, low, avg = summary([78, 92, 65, 88, 71])
print("Highest:", high)
print("Lowest :", low)
print("Average:", avg)

