upper = lower = digits = 0
with open("story.txt", "r") as f:
    for ch in f.read():
        if ch.isupper():
            upper = upper + 1
        elif ch.islower():
            lower = lower + 1
        elif ch.isdigit():
            digits = digits + 1

print("Uppercase:", upper)
print("Lowercase:", lower)
print("Digits   :", digits)

