stack = []

def push(item):
    stack.append(item)

def pop():
    if not stack:
        return "Underflow"
    return stack.pop()

def peek():
    if not stack:
        return "Empty"
    return stack[-1]

push("Maths")
push("Physics")
push("CS")

print("Top of stack:", peek())
print("Popped:", pop())
print("Popped:", pop())
print("Remaining:", stack)

